// Ã¢â€�â‚¬Ã¢â€�â‚¬ Step 1: Download Bike It stock file via SFTP (curl) Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬
// curl natively supports sftp:// URIs.
// File columns: SKU, Description, OnHandQuantity, SRP, Trade

const { execSync } = require('child_process');

const SFTP_USER = '34961@sftp.bikeit.co.uk';
const SFTP_PASS = '9471f0ac87600a2779fa76d8b8f' || '9471f0ac87600a2779fa76d8b8f';
const SFTP_URL  = 'sftp://sftp.bikeit.co.uk/stockprice.csv';

let csvText;
try {
  csvText = execSync(
    `curl -s --insecure --user "${SFTP_USER}:${SFTP_PASS}" "${SFTP_URL}"`,
    { timeout: 60000, maxBuffer: 50 * 1024 * 1024 }
  ).toString('utf8');
} catch (err) {
  throw new Error('SFTP download failed: ' + err.message);
}

// Ã¢â€�â‚¬Ã¢â€�â‚¬ Step 2: Parse CSV Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬
const lines = csvText.trim().split('\n');
if (lines.length < 2) throw new Error('Empty or invalid CSV from Bike It');

const headers = lines[0].split(',').map(h => h.trim().replace(/^"|"$/g, ''));
const rows = [];
for (let i = 1; i < lines.length; i++) {
  const cols = lines[i].split(',');
  if (cols.length < headers.length) continue;
  const row = {};
  headers.forEach((h, idx) => { row[h] = (cols[idx] || '').trim().replace(/^"|"$/g, ''); });
  rows.push(row);
}

// Ã¢â€�â‚¬Ã¢â€�â‚¬ Step 3: Filter & Transform Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬
const SUPABASE_URL = 'https://ddjuoeyaoxllockcusgf.supabase.co';
const SERVICE_KEY  = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImRkanVvZXlhb3hsbG9ja2N1c2dmIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc2NTM4ODM3OSwiZXhwIjoyMDgwOTY0Mzc5fQ.tQTpdQCkE-V-aCfdt7GgN5FF-IdXQzGCAEuRE6gNupE';
const CHUNK_SIZE   = 500;

const EXCLUDE_TERMS = [
  'bolt', 'bolts', 'nut', 'nuts', 'screw', 'screws',
  'fastener', 'fasteners', 'washer', 'washers',
  'rivet', 'rivets', 'split pin', 'circlip',
  'o-ring', 'o ring', 'oring'
];

const products = [];
let skipped_fastener = 0, skipped_lowvalue = 0, skipped_nosku = 0;

for (const r of rows) {
  const sku   = (r.SKU || '').trim();
  const title = (r.Description || '').trim();
  const qty   = parseInt(r.OnHandQuantity) || 0;
  const srp   = parseFloat(r.SRP) || 0;
  const trade = parseFloat(r.Trade) || 0;

  if (!sku) { skipped_nosku++; continue; }

  const tl = title.toLowerCase();
  if (EXCLUDE_TERMS.some(t => tl.includes(t))) { skipped_fastener++; continue; }
  if (srp < 50) { skipped_lowvalue++; continue; }

  products.push({
    sku,
    title,
    retail_price:  srp,
    trade_price:   trade || null,
    selling_price: trade > 0 ? Math.round(trade * 1.5 * 100) / 100 : null,
    stock_level:   qty <= 3 ? 0 : qty,
    supplier_id:   'BIKEIT',
    updated_at:    new Date().toISOString()
  });
}

// Ã¢â€�â‚¬Ã¢â€�â‚¬ Step 4: Batch upsert to Supabase Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬Ã¢â€�â‚¬
let upserted = 0, upsert_errors = 0;

for (let i = 0; i < products.length; i += CHUNK_SIZE) {
  const chunk = products.slice(i, i + CHUNK_SIZE);
  const res = await fetch(`${SUPABASE_URL}/rest/v1/products`, {
    method: 'POST',
    headers: {
      'apikey':        SERVICE_KEY,
      'Authorization': `Bearer ${SERVICE_KEY}`,
      'Content-Type':  'application/json',
      'Prefer':        'resolution=merge-duplicates,return=minimal'
    },
    body: JSON.stringify(chunk)
  });
  if (res.ok) {
    upserted += chunk.length;
  } else {
    upsert_errors += chunk.length;
    console.error(`Chunk ${Math.floor(i/CHUNK_SIZE)+1} error: ${await res.text()}`);
  }
}

return [{ json: {
  total_from_bikeit: rows.length,
  eligible:          products.length,
  skipped_fastener,
  skipped_lowvalue,
  skipped_nosku,
  upserted,
  upsert_errors,
  run_at: new Date().toISOString()
} }];

